```typescript
import { redirect } from '@sveltejs/kit';
import { createServerApi, serverApiUrl } from '/server/api';
import { CACHE_HEADERS } from '/server/cache';
import type { PageServerLoad } from './';

export const load: PageServerLoad = async ({ platform, cookies, locals, setHeaders }) => {
  // Auth guard
  if (!locals.user) {
    redirect(303, '/login?redirect=/account/notifications');
  }

  setHeaders(CACHE_HEADERS.PRIVATE);

  try {
    const identityUrl = serverApiUrl(platform, 'identity');
    const response = await fetch(
      `${identityUrl}/api/user/notification-preferences`,
      {
        headers: {
          'Cookie': `codex-session=${cookies.get('codex-session')}`,
        },
      }
    );

    if (!response.ok) {
      throw new Error('Failed to fetch notification preferences');
    }

    const result = await response.json();

    return {
      preferences: result.data ?? {
        emailMarketing: false,
        emailTransactional: true,
        emailDigest: false,
      },
    };
  } catch (error) {
    console.error('Failed to load notification preferences:', error);
    // Return defaults on error
    return {
      preferences: {
        emailMarketing: false,
        emailTransactional: true,
        emailDigest: false,
      },
    };
  }
};
```

### Step 2: Create Form Action
**File**: `apps/web/src/routes/(platform)/account/notifications/+page.server.ts` (same file)

```typescript
import { fail } from '@sveltejs/kit';
import { updateNotificationPreferencesSchema } from '@codex/validation';
import type { Actions } from './';

export const actions: Actions = {
  /**
   * Action: Update notification preferences
   * Route: POST /account/notifications?/update
   */
  default: async ({ request, cookies, platform }) => {
    const data = await request.formData();

    // Parse boolean values from checkboxes ("on" = true, undefined = false)
    const emailMarketing = data.get('emailMarketing') === 'on';
    const emailTransactional = data.get('emailTransactional') === 'on';
    const emailDigest = data.get('emailDigest') === 'on';

    // Validate with Zod schema
    const result = updateNotificationPreferencesSchema.safeParse({
      emailMarketing,
      emailTransactional,
      emailDigest,
    });

    if (!result.success) {
      return fail(400, {
        errors: result.error.flatten().fieldErrors,
      });
    }

    try {
      const identityUrl = serverApiUrl(platform, 'identity');
      const response = await fetch(`${identityUrl}/api/user/notification-preferences`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Cookie': `codex-session=${cookies.get('codex-session')}`,
        },
        body: JSON.stringify(result.data),
      });

      if (!response.ok) {
        const error = await response.json().catch(() => ({ message: 'Update failed' }));
        return fail(response.status, {
          error: error.message || 'Failed to update preferences',
        });
      }

      const updated = await response.json();

      return {
        success: true,
        preferences: updated.data,
      };
    } catch (error) {
      return fail(500, {
        error: 'An unexpected error occurred. Please try again.',
      });
    }
  },
};
```

