export const load: PageServerLoad = async ({ platform, cookies, locals, setHeaders }) => {
  // Auth guard (redundant with layout, but safe)
  if (!locals.user) {
    redirect(303, '/login?redirect=/account');
  }

  setHeaders(CACHE_HEADERS.PRIVATE);

  const api = createServerApi(platform, cookies);

  try {
    // Fetch current user profile from Identity API
    const response = await fetch(
      `${serverApiUrl(platform, 'identity')}/api/user/profile`,
      {
        headers: {
          'Cookie': `codex-session=${cookies.get('codex-session')}`,
        },
      }
    );

    if (!response.ok) {
      throw new Error('Failed to fetch profile');
    }

    const result = await response.json();
    return {
      user: result.data ?? locals.user,
    };
  } catch (error) {
    console.error('Failed to load profile:', error);
    // Return basic user from locals as fallback
    return {
      user: locals.user,
    };
  }
};
```

