### Step 2: Create Form Actions
**File**: `apps/web/src/routes/(platform)/account/+page.server.ts` (same file)

Add `Actions` type and actions object:

```typescript
import { fail, isRedirect, redirect } from '@sveltejs/kit';
import { updateProfileSchema } from '@codex/validation';
import type { Actions } from './';

export const actions: Actions = {
  /**
   * Action: Update profile (displayName, email)
   * Route: POST /account?/updateProfile
   */
  updateProfile: async ({ request, cookies, platform }) => {
    const data = await request.formData();
    const displayName = data.get('displayName');
    const email = data.get('email');

    // Validate with Zod schema
    const result = updateProfileSchema.safeParse({ 
      displayName: displayName?.toString(), 
      email: email?.toString() 
    });

    if (!result.success) {
      return fail(400, {
        errors: result.error.flatten().fieldErrors,
      });
    }

    try {
      const identityUrl = serverApiUrl(platform, 'identity');
      const response = await fetch(`${identityUrl}/api/user/profile`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          'Cookie': `codex-session=${cookies.get('codex-session')}`,
        },
        body: JSON.stringify(result.data),
      });

      if (!response.ok) {
        const error = await response.json().catch(() => ({ message: 'Update failed' }));
        return fail(response.status, {
          error: error.message || 'Failed to update profile',
        });
      }

      const updated = await response.json();

      // Return success with updated data for optimistic UI update
      return {
        success: true,
        user: updated.data,
      };
    } catch (error) {
      return fail(500, {
        error: 'An unexpected error occurred. Please try again.',
      });
    }
  },

  /**
   * Action: Upload avatar
   * Route: POST /account?/uploadAvatar
   */
  uploadAvatar: async ({ request, cookies, platform }) => {
    const data = await request.formData();
    const file = data.get('avatar');

    if (!file || typeof file === 'string') {
      return fail(400, {
        error: 'Please select a file to upload',
      });
    }

    // Validate file (max 5MB, image types)
    const MAX_SIZE = 5 * 1024 * 1024;
    const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp'];

    if (file.size > MAX_SIZE) {
      return fail(400, {
        error: 'Avatar must be under 5MB',
      });
    }

    if (!ALLOWED_TYPES.includes(file.type)) {
      return fail(400, {
        error: 'Avatar must be JPG, PNG, or WebP format',
      });
    }

    try {
      const identityUrl = serverApiUrl(platform, 'identity');
      const formData = new FormData();
      formData.append('avatar', file);

      const response = await fetch(`${identityUrl}/api/user/avatar`, {
        method: 'POST',
        headers: {
          'Cookie': `codex-session=${cookies.get('codex-session')}`,
        },
        body: formData,
      });

      if (!response.ok) {
        const error = await response.json().catch(() => ({ message: 'Upload failed' }));
        return fail(response.status, {
          error: error.message || 'Failed to upload avatar',
        });
      }

      const result = await response.json();

      return {
        success: true,
        avatarUrl: result.data.avatarUrl,
      };
    } catch (error) {
      return fail(500, {
        error: 'An unexpected error occurred. Please try again.',
      });
    }
  },

  /**
   * Action: Delete avatar
   * Route: POST /account?/deleteAvatar
   */
  deleteAvatar: async ({ cookies, platform }) => {
    try {
      const identityUrl = serverApiUrl(platform, 'identity');
      const response = await fetch(`${identityUrl}/api/user/avatar`, {
        method: 'DELETE',
        headers: {
          'Cookie': `codex-session=${cookies.get('codex-session')}`,
        },
      });

      if (!response.ok) {
        return fail(response.status, {
          error: 'Failed to remove avatar',
        });
      }

      return { success: true };
    } catch (error) {
      return fail(500, {
        error: 'An unexpected error occurred. Please try again.',
      });
    }
  },
};
```

