#### +page.server.ts

import { fail, redirect, isRedirect } from '@sveltejs/kit';
import { createServerApi } from '$lib/server/api';
import { logger } from '$lib/observability';
import type { Actions, PageServerLoad } from './$types';

interface PaymentInfo {
  hasPaymentMethod: boolean;
  cardBrand?: string;     // 'visa', 'mastercard', etc.
  cardLast4?: string;     // '4242'
  cardExpMonth?: number;  // 12
  cardExpYear?: number;   // 2027
}

export const load: PageServerLoad = async ({ parent, cookies, platform }) => {
  const { user } = await parent();

  // Load payment method info from Ecom API
  try {
    const api = createServerApi(platform, cookies);
    const paymentInfo = await api.fetch<{ data: PaymentInfo }>(
      'ecom', '/api/payment/method'
    );
    return { user, payment: paymentInfo.data };
  } catch {
    // No payment method or endpoint unavailable
    return {
      user,
      payment: { hasPaymentMethod: false } as PaymentInfo,
    };
  }
};

export const actions: Actions = {
  // Create a Stripe Customer Portal session and redirect
  managePayment: async ({ cookies, platform, request }) => {
    try {
      const api = createServerApi(platform, cookies);
      const result = await api.fetch<{ data: { url: string } }>(
        'ecom', '/api/payment/portal', undefined, {
          method: 'POST',
          body: JSON.stringify({
            returnUrl: request.headers.get('origin') + '/account/payment',
          }),
        }
      );

      if (result.data.url) {
        throw redirect(303, result.data.url);
      }

      return fail(500, { error: 'Could not create payment portal session.' });
    } catch (err) {
      if (isRedirect(err)) throw err;
      logger.error('Payment portal error', {
        error: err instanceof Error ? err.message : String(err),
      });
      return fail(500, { error: 'Failed to open payment settings. Please try again.' });
    }
  },
};

