#### +page.server.ts

import { fail, redirect, isRedirect } from '@sveltejs/kit';
import { serverApiUrl } from '$lib/server/api';
import { COOKIES, HEADERS, MIME_TYPES, getCookieConfig } from '@codex/constants';
import { extractSessionToken } from '$lib/server/auth-utils';
import { logger } from '$lib/observability';
import type { Actions, PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ url }) => {
  return {
    token: url.searchParams.get('token'),
  };
};

export const actions: Actions = {
  default: async ({ request, cookies, platform }) => {
    const data = await request.formData();
    const token = data.get('token') as string;
    const password = data.get('password') as string;
    const confirmPassword = data.get('confirmPassword') as string;

    // 1. Validate inputs
    if (!token) {
      return fail(400, { error: 'Missing reset token. Please request a new password reset link.' });
    }
    if (!password || password.length < 8) {
      return fail(400, { errors: { password: 'Password must be at least 8 characters' } });
    }
    if (password !== confirmPassword) {
      return fail(400, { errors: { confirmPassword: 'Passwords do not match' } });
    }

    try {
      // 2. Call Auth Worker
      const authUrl = serverApiUrl(platform, 'auth');
      const res = await fetch(authUrl + '/api/auth/reset-password', {
        method: 'POST',
        headers: { [HEADERS.CONTENT_TYPE]: MIME_TYPES.APPLICATION.JSON },
        body: JSON.stringify({ token, newPassword: password }),
      });

      if (!res.ok) {
        const error = await res.json().catch(() => ({}));
        if (res.status === 400 || res.status === 401) {
          return fail(400, { error: 'Invalid or expired reset link. Please request a new one.' });
        }
        return fail(res.status, { error: error.message || 'Failed to reset password.' });
      }

      // 3. Auto sign-in: Extract session token from response Set-Cookie
      const sessionToken = extractSessionToken(res);
      if (sessionToken) {
        const cookieConfig = getCookieConfig(platform?.env, request.headers.get('host') ?? undefined, {
          maxAge: COOKIES.SESSION_MAX_AGE,
        });
        cookies.set(COOKIES.SESSION_NAME, sessionToken, cookieConfig);
      }

      // 4. Redirect to library
      throw redirect(303, '/library');
    } catch (err) {
      if (isRedirect(err)) throw err;
      logger.error('Reset password error', { error: err instanceof Error ? err.message : String(err) });
      return fail(500, { error: 'An unexpected error occurred. Please try again.' });
    }
  },
};

### Key Implementation Notes

1. The Auth Worker endpoint is POST /api/auth/reset-password (NOT /api/auth/email/reset-password — verify against BetterAuth docs)
2. The request body should be: { token, newPassword } — BetterAuth expects newPassword field
3. On success, BetterAuth auto-creates a new session and returns Set-Cookie. Extract it using extractSessionToken() from $lib/server/auth-utils (same pattern as login)
4. Password validation: minimum 8 chars, at least one letter, at least one number (from @codex/validation passwordSchema)
5. On expired/invalid token, show error with link to /forgot-password to request a new one

### Auth Worker Endpoint Reference
- URL: POST /api/auth/reset-password
- Body: { "token": "...", "newPassword": "NewPass123" }
- Rate limit: 10 requests per 15 minutes per IP
- Success: 200 + Set-Cookie (auto sign-in)
- Errors: 400 (invalid token), 401 (expired token), 429 (rate limited)

### Acceptance Criteria
- [ ] Page loads with token from URL query param
- [ ] Missing token shows error message with link to /forgot-password
- [ ] Password validation: min 8 chars, matching confirmation
- [ ] Successful reset auto-signs user in (session cookie set) and redirects to /library
- [ ] Invalid/expired token shows error with link to request new reset
- [ ] Form works without JavaScript (progressive enhancement)
- [ ] Rate limiting shows appropriate message

