#### +page.server.ts
The verification should happen in the load function (server-side), NOT as a form action, because the user arrives via clicking an email link (GET request).

import { serverApiUrl } from '$lib/server/api';
import { COOKIES, getCookieConfig } from '@codex/constants';
import { extractSessionToken } from '$lib/server/auth-utils';
import { logger } from '$lib/observability';
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ url, cookies, platform, request }) => {
  const token = url.searchParams.get('token');

  // No token — show pending state (user just registered, waiting for email)
  if (!token) {
    return { status: 'pending' as const };
  }

  try {
    // Call Auth Worker to verify email
    const authUrl = serverApiUrl(platform, 'auth');
    const res = await fetch(authUrl + '/api/auth/verify-email?token=' + encodeURIComponent(token), {
      method: 'GET',
      headers: {
        Cookie: cookies.get(COOKIES.SESSION_NAME)
          ? COOKIES.SESSION_NAME + '=' + cookies.get(COOKIES.SESSION_NAME)
          : '',
      },
    });

    if (!res.ok) {
      const error = await res.json().catch(() => ({}));
      return {
        status: 'error' as const,
        error: error.message || 'Invalid or expired verification link.',
      };
    }

    // Extract session token if BetterAuth auto-signs in
    const sessionToken = extractSessionToken(res);
    if (sessionToken) {
      const cookieConfig = getCookieConfig(platform?.env, request.headers.get('host') ?? undefined, {
        maxAge: COOKIES.SESSION_MAX_AGE,
      });
      cookies.set(COOKIES.SESSION_NAME, sessionToken, cookieConfig);
    }

    return { status: 'success' as const };
  } catch (err) {
    logger.error('Email verification error', { error: err instanceof Error ? err.message : String(err) });
    return {
      status: 'error' as const,
      error: 'Something went wrong. Please try again.',
    };
  }
};

