    if (template.scope === 'global' && ctx.user.role !== 'platform_owner') {
      return ctx.json({ error: 'Access denied' }, 403);
    }

    // Create service
    const brandingService = new BrandingSettingsService({ db });
    const contactService = new ContactSettingsService({ db });
    const emailProvider = createEmailProvider({
      useMock: ctx.env.USE_MOCK_EMAIL === 'true',
      resendApiKey: ctx.env.RESEND_API_KEY,
      mailhogUrl: ctx.env.MAILHOG_URL,
    });

    const notificationService = new NotificationService({
      db,
      emailProvider,
      brandingService,
      contactService,
      fromEmail: ctx.env.FROM_EMAIL || 'noreply@example.com',
      fromName: ctx.env.FROM_NAME,
      environment: ctx.env.ENVIRONMENT || 'development',
    });

    const result = await notificationService.sendEmail({
      templateName: template.name,
      recipientEmail: ctx.input.body.recipientEmail,
      recipientName: 'Test User',
      data: ctx.input.body.data,
      organizationId: template.organizationId ?? undefined,
      creatorId: template.creatorId ?? undefined,
    });

    return { data: result };
  },
}));

export { app as previewRoutes };
```

