  const { platform, cookies } = getRequestEvent();
  const api = createServerApi(platform, cookies);
  return api.access.getProgress(contentId);
});

// Save playback progress (command for mutations)
export const savePlaybackProgress = command(
  z.object({
    contentId: z.string().uuid(),
    positionSeconds: z.number().min(0),
    durationSeconds: z.number().positive(),
  }),
  async ({ contentId, positionSeconds, durationSeconds }) => {
    const { platform, cookies } = getRequestEvent();
    const api = createServerApi(platform, cookies);

    const completed = durationSeconds > 0 && 
      (positionSeconds / durationSeconds) > 0.9;

    return api.access.saveProgress(contentId, {
      positionSeconds,
      durationSeconds,
      completed,
    });
  }
