# Phase 2.1: Auth Remote Functions

Create remote functions for authentication flows using SvelteKit's `form` for progressive enhancement.

## Files to Create

### `apps/web/src/lib/remote/auth.remote.ts`

```typescript
import { form, query, getRequestEvent } from '$app/server';
import { z } from 'zod';
import { createServerApi } from '$lib/server/api';
import { redirect } from '@sveltejs/kit';
import { COOKIES } from '@codex/constants';

// Login form with progressive enhancement
export const loginForm = form(
  z.object({
    email: z.string().email(),
    _password: z.string().min(8),  // underscore = don't repopulate
  }),
  async ({ email, _password }) => {
    const { platform, cookies } = getRequestEvent();

    // Call auth worker directly for Set-Cookie header access
    const authUrl = serverApiUrl(platform, 'auth');
    const res = await fetch(`${authUrl}/api/auth/sign-in/email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password: _password }),
    });

    if (!res.ok) {
      const error = await res.json();
      return { success: false, error: error.message };
    }

    // Extract and set session cookie
    const setCookie = res.headers.get('set-cookie');
    if (setCookie) {
      const match = setCookie.match(/codex-session=([^;]+)/);
      if (match) {
        cookies.set(COOKIES.SESSION_NAME, match[1], {
          path: '/',
          httpOnly: true,
          secure: !platform?.env?.dev,
          sameSite: 'lax',
        });
      }
    }

    redirect(303, '/library');
  }
);

// Register form
export const registerForm = form(
  z.object({
    name: z.string().min(2),
    email: z.string().email(),
    _password: z.string().min(8),
  }),
  async ({ name, email, _password }) => {
    const { platform, cookies } = getRequestEvent();
    const authUrl = serverApiUrl(platform, 'auth');

    const res = await fetch(`${authUrl}/api/auth/sign-up/email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, email, password: _password }),
    });

    if (!res.ok) {
      const error = await res.json();
      return { success: false, error: error.message };
    }

    // Handle session cookie same as login
    // ... (same pattern)

    redirect(303, '/library');
  }
);

// Get current session (for components)
export const getSession = query(async () => {
  const { platform, cookies } = getRequestEvent();
  const api = createServerApi(platform, cookies);

  try {
    return await api.auth.getSession();
  } catch {
    return { user: null, session: null };
  }
});

// Logout command
export const logout = command(async () => {
  const { cookies } = getRequestEvent();
  cookies.delete(COOKIES.SESSION_NAME, { path: '/' });
  redirect(303, '/login');
});
```

