### Step 1: Define Validation Schema

**File**: `packages/validation/src/content-schemas.ts`

Add new schema for public content queries:

```typescript
// Public content listing (no auth required when visibility=public)
export const publicContentQuerySchema = z.object({
  // Organization filters
  organizationSlug: z.string().min(1).optional(),
  organizationId: z.string().uuid().optional(),

  // Public access gatekeeper
  visibility: z.enum(['public']).optional(), // Only 'public' allowed for unauthenticated

  // Content filters
  status: z.enum(['draft', 'published', 'archived']).optional(),
  contentType: z.enum(['video', 'audio', 'written']).optional(),
  category: z.string().optional(),

  // Search
  search: z.string().max(200).optional(),

  // Sorting
  sortBy: z.enum(['createdAt', 'publishedAt', 'title', 'viewCount']).optional(),
  sortOrder: z.enum(['asc', 'desc']).optional(),

  // Pagination
  page: z.coerce.number().min(1).default(1),
  limit: z.coerce.number().min(1).max(100).default(20),
});

export type PublicContentQuery = z.infer<typeof publicContentQuerySchema>;
```

**Security Note**: The `visibility` field is the gatekeeper. When set to 'public', we know the request is for public content and can skip authentication.

