### Step 2: Add Service Method

**File**: `packages/content/src/services/content-service.ts`

Add new method for public content listing:

```typescript
/**
 * List public content (no authentication required)
 * 
 * Security:
 * - Only returns published, public visibility content
 * - Excludes soft-deleted content
 * - Filters by organization if specified
 * - No creator scoping (public access)
 * 
 * @param filters - Public query filters
 * @param pagination - Pagination parameters
 * @returns Paginated public content list
 */
async listPublic(
  filters: PublicContentFilters = {},
  pagination: PaginationParams = {
    page: 1,
    limit: PAGINATION.DEFAULT,
  }
): Promise<PaginatedListResponse<PublicContentItem>> {
  try {
    const { limit, offset } = withPagination(pagination);

    // Build WHERE conditions for public content
    const whereConditions = [
      eq(content.status, 'published'), // Only published
      eq(content.visibility, 'public'), // Only public visibility
      isNull(content.deletedAt), // Not deleted
    ];

    // Optional organization filter
    if (filters.organizationSlug) {
      // Need to join with organizations table
      whereConditions.push(
        eq(organizations.slug, filters.organizationSlug)
      );
    }
    if (filters.organizationId) {
      whereConditions.push(
        eq(content.organizationId, filters.organizationId)
      );
    }

    // Optional type filter
    if (filters.contentType) {
      whereConditions.push(eq(content.contentType, filters.contentType));
    }

    // Optional search
    if (filters.search) {
      const searchCondition = or(
        ilike(content.title, `%${filters.search}%`),
        ilike(content.description ?? '', `%${filters.search}%`)
      );
      if (searchCondition) {
        whereConditions.push(searchCondition);
      }
    }

    // Sort by publishedAt (default) or createdAt
    const sortColumn = filters.sortBy || 'publishedAt';
    const sortOrder = filters.sortOrder || 'desc';
    const orderByClause =
      sortOrder === 'desc'
        ? desc(content[sortColumn])
        : asc(content[sortColumn]);

    // Get items with organization relation
    let query = this.db.query.content.findMany({
      where: and(...whereConditions),
      limit,
      offset,
      orderBy: [orderByClause],
      with: {
        organization: {
          columns: {
            id: true,
            name: true,
            slug: true,
            logoUrl: true,
          },
        },
        creator: {
          columns: {
            id: true,
            name: true,
          },
        },
        mediaItem: {
          columns: {
            id: true,
            thumbnailUrl: true,
            duration: true,
          },
        },
      },
    });

    const items = await query;

    // Get total count
    const countResult = await this.db
      .select({ total: count() })
      .from(content)
      .where(and(...whereConditions));

    const totalRecord = countResult[0];
    if (\!totalRecord) {
      throw new Error('Failed to get content count');
    }

    const { total } = totalRecord;
    const totalCount = Number(total);
    const totalPages = Math.ceil(totalCount / limit);

    return {
      items: items as PublicContentItem[], // Type assertion for public projection
      pagination: {
        page: pagination.page,
        limit,
        total: totalCount,
        totalPages,
      },
    };
  } catch (error) {
    throw wrapError(error, { filters, pagination });
  }
}
```

