### Step 3: Add API Route

**File**: `workers/content-api/src/routes/content.ts`

Add new public route:

```typescript
/**
 * GET /api/content/public
 * List public content (no auth required)
 *
 * Security: No auth required, returns public-safe projection
 * Cache: Public CDN cache (5min)
 */
app.get(
  '/public',
  procedure({
    policy: { auth: 'none' }, // Public access
    rateLimit: 'api',
    input: { query: publicContentQuerySchema },
    handler: async (ctx): Promise<ContentListResponse> => {
      const { visibility, ...filters } = ctx.input.query;

      // Verify visibility=public for security
      // (this is already enforced by schema, but double-check)
      if (visibility \!== 'public') {
        throw new z.ZodError([
          {
            code: z.ZodIssueCode.custom,
            path: ['visibility'],
            message: 'Only public content is accessible without authentication',
          },
        ]);
      }

      return await ctx.services.content.listPublic(
        filters,
        {
          page: ctx.input.query.page,
          limit: ctx.input.query.limit,
        }
      );
    },
  })
);
```

**Alternative**: Extend existing `GET /api/content` route to conditionally allow public access:

```typescript
app.get(
  '/',
  procedure({
    policy: { 
      // Allow unauthenticated access ONLY when visibility=public
      auth: (input) => input.query.visibility === 'public' ? 'none' : 'required'
    },
    input: { query: contentQuerySchema.extend({ visibility: z.enum(['public', 'purchased_only', 'members_only']).optional() }) },
    handler: async (ctx) => {
      if (ctx.input.query.visibility === 'public') {
        // Public listing path
        return await ctx.services.content.listPublic(ctx.input.query, {
          page: ctx.input.query.page,
          limit: ctx.input.query.limit,
