/**
 * List public content for an organization
 * Unauthenticated, cacheable
 *
 * Usage: {#await listPublicOrgContent(slug, params) as result}
 */
export const listPublicOrgContent = query(
  z.object({
    slug: z.string().min(1),
    q: z.string().optional(),
    type: z.enum(['video', 'written', 'audio']).optional(),
    sort: z.enum(['newest', 'popular', 'az']).optional(),
    page: z.coerce.number().min(1).default(1),
    limit: z.coerce.number().min(1).max(50).default(12),
  }),
  async (params) => {
    const { platform } = getRequestEvent();
    const contentApiUrl = serverApiUrl(platform, 'content');

    // Build query string
    const searchParams = new URLSearchParams();
    searchParams.set('organizationSlug', params.slug);
    searchParams.set('visibility', 'public');
    searchParams.set('status', 'published');
    if (params.q) searchParams.set('search', params.q);
    if (params.type) searchParams.set('type', params.type);
    if (params.sort) searchParams.set('sort', params.sort);
    searchParams.set('page', String(params.page));
    searchParams.set('limit', String(params.limit));

    // TODO: Update endpoint once Codex-qv2 is complete
    const response = await fetch(`${contentApiUrl}/api/content?${searchParams}`);

    if (!response.ok) {
      // Return empty result if endpoint not ready
      return { items: [], total: 0, page: 1, limit: params.limit, totalPages: 0 };
    }

    return await response.json();
  }
);
```

