import { CACHE_HEADERS } from '/server/cache';
import { listPublicOrgContent } from '/remote/content.remote';
import type { Actions, PageServerLoad } from './';

export const load: PageServerLoad = async ({ url, params }) => {
  const { slug } = params;
  const searchParams = url.searchParams;

  // Extract filter params from URL
  const q = searchParams.get('q') ?? undefined;
  const type = searchParams.get('type') ?? undefined;
  const sort = (searchParams.get('sort') ?? 'newest') as 'newest' | 'popular' | 'az';
  const page = Number(searchParams.get('page') ?? '1');

  // Fetch content from API
  const result = await listPublicOrgContent({
    slug,
    q,
    type: type as any,
    sort,
    page,
    limit: 12,
  });

  return {
    ...result,
    filters: { q, type, sort, page },
  };
};

export const actions: Actions = {};
```

**Key Pattern**: URL state drives all filters/search/pagination. This enables:
