```typescript
import { createServerApi } from '$lib/server/api';
import { CACHE_HEADERS } from '$lib/server/cache';
import { error } from '@sveltejs/kit';
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ params, platform, cookies, url, setHeaders }) => {
  setHeaders(CACHE_HEADERS.DYNAMIC_PUBLIC);

  const api = createServerApi(platform, cookies);
  const username = params.username;

  // Fetch creator profile
  try {
    const creatorResponse = await fetch(
      `${serverApiUrl(platform, 'org')}/api/organizations/public/creators/${username}`
    );
    if (!creatorResponse.ok) {
      throw error(404, 'Creator not found');
    }
    const creator = await creatorResponse.json();

    // Fetch creator's published content
    const params = new URLSearchParams();
    params.set('creatorId', creator.data.id);
    params.set('status', 'published');
    params.set('visibility', 'public');

    const page = url.searchParams.get('page');
    if (page) params.set('page', page);

    const contentResponse = await api.content.list(params);

    return {
      creator: creator.data,
      content: contentResponse.items ?? [],
      pagination: contentResponse.pagination,
    };
  } catch (err) {
    if ((err as any).status === 404) throw err;
    console.error('Failed to load creator profile:', err);
    throw error(500, 'Failed to load profile');
  }
};
```

