  it('renders both HTML and text versions', () => {
    const result = renderEmailTemplate({
      htmlTemplate: '<p>Hello {{userName}}</p>',
      textTemplate: 'Hello {{userName}}',
      data: { userName: 'John' },
      allowedTokens: ['userName'],
