import { fail } from '@sveltejs/kit';
import { createServerApi } from '$lib/server/api';
import { logger } from '$lib/observability';
import type { Actions, PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ parent }) => {
  // User data comes from parent layout (account +layout.server.ts)
  const { user } = await parent();
  return { user };
};

export const actions: Actions = {
  updateProfile: async ({ request, cookies, platform, locals }) => {
    const data = await request.formData();
    const name = (data.get('name') as string)?.trim();

    // Validate
    if (name !== undefined && name.length > 100) {
      return fail(400, { errors: { name: 'Name must be 100 characters or less' }, name });
    }

    try {
      const api = createServerApi(platform, cookies);
      // Call Identity API to update user profile
      // Endpoint TBD — likely PATCH /api/users/me or PATCH /api/identity/profile
      await api.fetch('identity', '/api/users/me', undefined, {
        method: 'PATCH',
        body: JSON.stringify({ name }),
      });

      return { success: true, name };
    } catch (err) {
      logger.error('Profile update error', { error: err instanceof Error ? err.message : String(err) });
      return fail(500, { error: 'Failed to update profile. Please try again.', name });
    }
  },
};

